mapper.select:
SELECT COUNT(*) FROM MEMBER
AND LOGIN_ID LIKE '%' || #{dto.keyword} || '%' AND NAME LIKE '%' || #{dto.keyword} || '%'
AND UPPER(GENDER) = UPPER(#{dto.gender}) AND ROLE = #{dto.role}

SELECT MEMBER_ID as "memberId", LOGIN_ID as "loginId", NAME as "name", GENDER as "gender", 
       AGE as "age", ROLE as "role", CREATED_AT as "createdAt", LAST_LOGIN_AT as "lastLoginAt"
FROM MEMBER WHERE MEMBER_ID = #{memberId}

SELECT MEMBER_ID as "memberId", LOGIN_ID as "loginId", PASSWORD as "password", NAME as "name", 
       GENDER as "gender", AGE as "age", ROLE as "role", CREATED_AT as "createdAt"
FROM MEMBER WHERE LOGIN_ID = #{loginId}
